import React, { useState } from "react";

export default function QuestionStep({ dimension, phase, setPhase, onComplete }) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState({});

  const questions = dimension.questions;
  const currentQuestion = questions[currentIndex];

  const handleAnswer = (value) => {
    setScore((prev) => ({
      ...prev,
      [value]: (prev[value] || 0) + 1
    }));

    if (currentIndex + 1 < questions.length) {
      setCurrentIndex(currentIndex + 1);
    } else {
      setPhase("result");
    }
  };

  const finalResult = (score.E || 0) >= (score.I || 0) ? "E" : "I";

  return (
    <div className="test-card">

      {/* ===== INTRO ===== */}
      {phase === "intro" && (
        <>
          <h2>{dimension.title}</h2>
          <p style={{ color: "#b0bec5", margin: "24px 0 36px" }}>
            {dimension.intro}
          </p>
          <button className="test-button" onClick={() => setPhase("question")}>
            დაიწყე
          </button>
        </>
      )}

      {/* ===== QUESTIONS ===== */}
      {phase === "question" && (
        <>
          <h2>{dimension.title}</h2>
          <p style={{ marginBottom: "20px" }}>
            კითხვა {currentIndex + 1} / {questions.length}
          </p>
          <p style={{ marginBottom: "26px" }}>{currentQuestion.text}</p>

          <div style={{ display: "flex", gap: "20px" }}>
            <button onClick={() => handleAnswer(currentQuestion.a.value)}>
              {currentQuestion.a.text}
            </button>
            <button onClick={() => handleAnswer(currentQuestion.b.value)}>
              {currentQuestion.b.text}
            </button>
          </div>
        </>
      )}

      {/* ===== RESULT ===== */}
      {phase === "result" && (
        <>
          <img
            src={`/images/${finalResult}.png`}
            alt={finalResult}
            style={{ maxWidth: "150px", marginBottom: "20px" }}
          />
          <p style={{ marginBottom: "30px" }}>
            {dimension.descriptions[finalResult]}
          </p>
          <button className="test-button" onClick={() => onComplete(finalResult)}>
            განაგრძე →
          </button>
        </>
      )}

    </div>
  );
}
